.chart-container {
  max-width: 700px;
  margin: 0 auto;
  padding: 20px;
  background: #fff;
  border-radius: 12px;
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
}

.chart-container h2 {
  text-align: center;
  margin-bottom: 20px;
  color: #333;
}

.canvas-wrapper {
  width: 100%;
  height: 400px; /* Tăng chiều cao biểu đồ */
}

canvas {
  width: 100% !important;
  height: 100% !important;
}
